27	pub const PROGRAM_DELIMITER: &str = "// --- Next Program --- //";
28	pub const MODULE_DELIMITER: &str = "// --- Next Module:";
29	
30	/// Fully compiles a Leo source string into bytecode.
31	///
32	/// This performs the entire compilation pipeline:
33	/// - splits embedded modules,
34	/// - initializes a compiler with the given `handler`, `node_builder`, and `import_stubs`,
35	/// - compiles the main program and its modules,
36	/// - returns:
37	///     * `(main_bytecode, imported_bytecodes)` and
38	///     * the compiled program's name.
39	///
40	/// Used when compiling the final (top-level) program in a test.
41	#[allow(clippy::type_complexity)]
42	pub fn whole_compile(
43	    source: &str,
44	    handler: &Handler,
45	    node_builder: &Rc<NodeBuilder>,
46	    import_stubs: IndexMap<Symbol, Stub>,
47	) -> Result<(Compiled, String), LeoError> {
48	    let (main_source, modules) = split_modules(source);
49	
50	    let mut compiler = Compiler::new(
51	        None,
52	        /* is_test */ false,
53	        handler.clone(),
54	        node_builder.clone(),
55	        "/fakedirectory-wont-use".into(),
56	        None,
57	        import_stubs,
58	        NetworkName::TestnetV0,
59	    );
60	
61	    // Prepare module references
62	    let module_refs: Vec<(&str, FileName)> =
63	        modules.iter().map(|(src, path)| (src.as_str(), FileName::Custom(path.to_string_lossy().into()))).collect();
64	
65	    let filename = FileName::Custom("compiler-test".into());
66	    let bytecodes = compiler.compile(&main_source, filename, &module_refs)?;
67	
68	    Ok((bytecodes, compiler.program_name.unwrap()))
69	}
70	
71	/// Parses a Leo source string into an AST `Program` without generating bytecode.
72	///
73	/// This runs only the front-end portion of the pipeline:
74	/// - splits embedded modules,
75	/// - initializes a compiler with the given `handler`, `node_builder`, and `import_stubs`,
76	/// - parses the main program and its modules into an AST,
77	/// - returns the parsed `Program` and the program's name.
78	///
79	/// Used for intermediate programs that are imported by the final one.
80	pub fn parse_program(
81	    source: &str,
82	    handler: &Handler,
83	    node_builder: &Rc<NodeBuilder>,
84	    import_stubs: IndexMap<Symbol, Stub>,
85	) -> Result<(Program, String), LeoError> {
86	    let (main_source, modules) = split_modules(source);
87	
88	    let mut compiler = Compiler::new(
89	        None,
90	        /* is_test */ false,
91	        handler.clone(),
92	        node_builder.clone(),
93	        "/fakedirectory-wont-use".into(),
94	        None,
95	        import_stubs,
96	        NetworkName::TestnetV0,
97	    );
98	
99	    // Prepare module references
100	    let module_refs: Vec<(&str, FileName)> =
101	        modules.iter().map(|(src, path)| (src.as_str(), FileName::Custom(path.to_string_lossy().into()))).collect();
102	
103	    let filename = FileName::Custom("compiler-test".into());
104	    let program = compiler.parse_and_return_program(&main_source, filename, &module_refs)?;
105	
106	    Ok((program, compiler.program_name.unwrap()))
107	}
