109	/// Parses a Leo library from the given source for use in compiler tests.
110	///
111	/// The source may contain `// --- Next Module: name --- //` delimiters to embed
112	/// submodule source files, using the same protocol as `parse_program`.
113	pub fn parse_library(
114	    library_name: &str,
115	    source: &str,
116	    handler: &Handler,
117	    node_builder: &Rc<NodeBuilder>,
118	) -> Result<Library, LeoError> {
119	    let (main_source, modules) = split_modules(source);
120	
121	    let mut compiler = Compiler::new(
122	        None,
123	        /* is_test */ false,
124	        handler.clone(),
125	        node_builder.clone(),
126	        "/fakedirectory-wont-use".into(),
127	        None,
128	        IndexMap::new(),
129	        NetworkName::TestnetV0,
130	    );
131	
132	    let filename = FileName::Custom("compiler-test".into());
133	    let module_refs: Vec<(&str, FileName)> =
134	        modules.iter().map(|(src, path)| (src.as_str(), FileName::Custom(path.to_string_lossy().into()))).collect();
135	
136	    compiler.parse_and_return_library(library_name, &main_source, filename, &module_refs)
137	}
138	
139	/// Splits a single source string into a main source and a list of module
140	/// `(source, path)` pairs using the MODULE_DELIMITER protocol.
141	///
142	/// Shared by both `whole_compile` and `parse`.
143	fn split_modules(source: &str) -> (String, Vec<(String, PathBuf)>) {
144	    // Fast path — no modules at all
145	    if !source.contains(MODULE_DELIMITER) {
146	        return (source.to_string(), Vec::new());
147	    }
148	
149	    let mut main_source = String::new();
150	    let mut modules: Vec<(String, PathBuf)> = Vec::new();
151	
152	    let mut current_module_path: Option<PathBuf> = None;
153	    let mut current_module_source = String::new();
154	
155	    for line in source.lines() {
156	        if let Some(rest) = line.strip_prefix(MODULE_DELIMITER) {
157	            // Save previous block
158	            if let Some(path) = current_module_path.take() {
159	                modules.push((current_module_source.clone(), path));
160	                current_module_source.clear();
161	            } else {
162	                main_source = current_module_source.clone();
163	                current_module_source.clear();
164	            }
165	
166	            // Start new module
167	            let trimmed_path = rest.trim().trim_end_matches(" --- //");
168	            current_module_path = Some(PathBuf::from(trimmed_path));
169	        } else {
170	            current_module_source.push_str(line);
171	            current_module_source.push('\n');
172	        }
173	    }
174	
175	    // Push the last module or main
176	    if let Some(path) = current_module_path {
177	        modules.push((current_module_source.clone(), path));
178	    } else {
179	        main_source = current_module_source;
180	    }
181	
182	    (main_source, modules)
183	}
