32	// This determines how the dependent programs are imported. They can either be imported as Leo
33	// programs directly (which usually allows more features to be supported such as external generic
34	// structs, etc.) or as Aleo programs (such as depending on the deployed credits.aleo).
35	#[derive(PartialEq)]
36	enum StubType {
37	    FromLeo,
38	    FromAleo,
39	}
40	
41	/// Runs a compiler test by compiling a sequence of stub programs followed by a final program.
42	///
43	/// The input string may contain multiple sources separated by `PROGRAM_DELIMITER`, where earlier
44	/// entries represent dependencies and the final entry is the program under test. Dependencies are
45	/// compiled either as Leo stubs or Aleo bytecode depending on `stub_type`, then registered into a
46	/// `Process` to validate correctness and linking behavior.
47	///
48	/// Library dependencies are parsed separately and tracked so their parent relationships can be
49	/// reconstructed for the final program. The function returns all resulting bytecodes concatenated
50	/// in source order using the same delimiter.
51	fn run_test(stub_type: StubType, test: &str, handler: &Handler, node_builder: &Rc<NodeBuilder>) -> Result<String, ()> {
52	    let mut process = Process::<TestnetV0>::load().unwrap();
53	
54	    let mut import_stubs = IndexMap::new();
55	
56	    let mut bytecodes = Vec::<String>::new();
57	
58	    let sources: Vec<&str> = test.split(super::test_utils::PROGRAM_DELIMITER).collect();
59	
60	    // Helper: parse and register Aleo program into `process`.
61	    // Note that this performs an additional validity check on the bytecode.
62	    let mut add_aleo_program = |code: &str| -> Result<(), ()> {
63	        let program = handler.extend_if_error(ProgramCore::from_str(code).map_err(LeoError::Anyhow))?;
64	        handler.extend_if_error(process.add_program(&program).map_err(LeoError::Anyhow))?;
65	        Ok(())
66	    };
67	
68	    let (last, rest) = sources.split_last().expect("non-empty sources");
69	
70	    // Pre-parse all `// --- aleo stub --- //` sections. These contain raw Aleo bytecode and
71	    // are always treated as FromAleo stubs. We parse them first so they're available for Leo
72	    // programs to reference, regardless of file order.
73	    let mut aleo_lookup: IndexMap<Symbol, (Stub, String)> = IndexMap::new();
74	    for source in rest {
75	        if let Some(aleo_source) = super::test_utils::extract_aleo_stub_header(source) {
76	            let program = handler
77	                .extend_if_error(disassemble_from_str::<TestnetV0>("", aleo_source).map_err(|err| err.into()))?;
78	            let name = program.stub_id.as_symbol();
79	            let stub: Stub = program.into();
80	            aleo_lookup.insert(name, (stub, aleo_source.to_string()));
81	        }
82	    }
83	
84	    // In FromAleo mode, insert aleo stubs early so Leo programs can reference them,
85	    // and register them in the Process for validation.
86	    // In FromLeo mode, we defer insertion until after Leo programs to reproduce the
87	    // real-world ordering where FromAleo stubs may appear after FromLeo stubs.
88	    if stub_type == StubType::FromAleo {
89	        for (name, (stub, aleo_source)) in &aleo_lookup {
90	            import_stubs.insert(*name, stub.clone());
91	            add_aleo_program(aleo_source)?;
92	        }
93	    }
94	
95	    for source in rest {
96	        // Skip aleo stub sections; they are handled above.
97	        if super::test_utils::extract_aleo_stub_header(source).is_some() {
98	            continue;
99	        }
100	
101	        match stub_type {
102	            StubType::FromLeo => {
103	                if let Some((library_name, library_source)) = super::test_utils::extract_library_header(source) {
104	                    // Handle library dependencies (always Leo dependencies).
105	                    let library = handler.extend_if_error(super::test_utils::parse_library(
106	                        &library_name,
107	                        library_source,
108	                        handler,
109	                        node_builder,
110	                    ))?;
111	
112	                    import_stubs.insert(Symbol::intern(&library_name), library.into());
113	                } else {
114	                    // Handle program dependencies. Treat them as Leo direct dependencies.
115	                    // Merge aleo_lookup into the stubs passed for parsing so that Leo programs
116	                    // can reference types from aleo stubs.
117	                    let mut stubs_for_parse = import_stubs.clone();
118	                    for (name, (stub, _)) in &aleo_lookup {
119	                        stubs_for_parse.insert(*name, stub.clone());
120	                    }
121	
122	                    let (program, program_name) = handler.extend_if_error(super::test_utils::parse_program(
123	                        source,
124	                        handler,
125	                        node_builder,
126	                        stubs_for_parse,
127	                    ))?;
128	
129	                    import_stubs.insert(Symbol::intern(&program_name), program.into());
130	                }
131	
132	                if handler.err_count() != 0 {
133	                    return Err(());
134	                }
135	            }
136	
137	            StubType::FromAleo => {
138	                if let Some((library_name, library_source)) = super::test_utils::extract_library_header(source) {
139	                    // Handle library dependencies (always Leo dependencies).
140	                    let library = handler.extend_if_error(super::test_utils::parse_library(
141	                        &library_name,
142	                        library_source,
143	                        handler,
144	                        node_builder,
145	                    ))?;
146	
147	                    import_stubs.insert(Symbol::intern(&library_name), library.into());
148	                } else {
149	                    // Handle program dependencies. Treat them as Aleo dependencies by fully compiling them individually first.
150	
151	                    // Before compiling, register this program as a parent of all known libraries
152	                    // so that library constants are visible during compilation.
153	                    let program_name_for_parents =
154	                        handler.extend_if_error(super::test_utils::extract_program_name(source, handler))?;
155	                    let program_symbol = Symbol::intern(&program_name_for_parents);
156	                    for stub in import_stubs.values_mut() {
157	                        if stub.is_library() {
158	                            stub.add_parent(program_symbol);
159	                        }
160	                    }
161	
162	                    let (programs, program_name) = handler.extend_if_error(super::test_utils::whole_compile(
163	                        source,
164	                        handler,
165	                        node_builder,
166	                        import_stubs.clone(),
167	                    ))?;
168	
169	                    // Parse the bytecode as an Aleo program.
170	                    // Note that this function checks that the bytecode is well-formed.
171	                    add_aleo_program(&programs.primary.bytecode)?;
172	
173	                    let program = handler.extend_if_error(
174	                        disassemble_from_str::<TestnetV0>(&program_name, &programs.primary.bytecode)
175	                            .map_err(|err| err.into()),
176	                    )?;
177	
178	                    import_stubs.insert(Symbol::intern(&program_name), program.into());
179	
180	                    if handler.err_count() != 0 {
181	                        return Err(());
182	                    }
183	
184	                    bytecodes.push(programs.primary.bytecode);
185	                }
186	            }
187	        };
188	    }
189	
190	    // In FromLeo mode, insert aleo stubs AFTER all Leo programs in import_stubs.
191	    // This mirrors the real-world ordering where the package manager may place FromAleo stubs
192	    // after FromLeo stubs in the compilation unit order.
193	    if stub_type == StubType::FromLeo {
194	        for (name, (stub, _)) in &aleo_lookup {
195	            import_stubs.insert(*name, stub.clone());
196	        }
197	    }
198	
199	    // Extract the name of the final program so we can treat it as a parent.
200	    let final_program_name = handler.extend_if_error(super::test_utils::extract_program_name(last, handler))?;
201	    let final_symbol = Symbol::intern(&final_program_name);
202	
203	    // Populate parents for libraries: parents come after them in the stub order
204	    {
205	        let symbols: Vec<Symbol> = import_stubs.keys().copied().collect();
206	
207	        for (i, symbol) in symbols.iter().enumerate() {
208	            if let Some(Stub::FromLibrary { parents, .. }) = import_stubs.get_mut(symbol) {
209	                // Parents that appear later in the stub order
210	                parents.extend(symbols[i + 1..].iter().copied());
211	
212	                // The final program also depends on earlier libraries
213	                parents.insert(final_symbol);
214	            }
215	        }
216	    }
217	
218	    // Full compile for final program.
219	    let (compiled, _program_name) =
220	        handler.extend_if_error(super::test_utils::whole_compile(last, handler, node_builder, import_stubs.clone()))?;
221	
222	    // Only error out if there are errors. Warnings are okay but we still want to print them later.
223	    if handler.err_count() != 0 {
224	        return Err(());
225	    }
226	
227	    // Add imports but only if the imports are in Leo form. Aleo stubs are added earlier.
228	    if stub_type == StubType::FromLeo {
229	        // Register aleo stubs in the Process first so that compiled imports
230	        // (which may depend on them) can be validated.
231	        for (_, (_, aleo_source)) in &aleo_lookup {
232	            add_aleo_program(aleo_source)?;
233	        }
234	        for import in &compiled.imports {
235	            add_aleo_program(&import.bytecode)?;
236	            bytecodes.push(import.bytecode.clone());
237	        }
238	    }
239	
240	    // Add main program.
241	    let primary_bytecode = compiled.primary.bytecode.clone();
242	    add_aleo_program(&primary_bytecode)?;
243	    bytecodes.push(primary_bytecode);
244	
245	    Ok(bytecodes.iter().format(&format!("{}\n", super::test_utils::PROGRAM_DELIMITER)).to_string())
246	}
247	
248	/// Runs the test twice:
249	/// 1. Treating dependencies as Leo
250	/// 2. Treating dependencies as Aleo
251	///
252	/// If the outputs differ, both results are reported with a clear explanation.
253	fn runner(source: &str) -> String {
254	    let from_leo_output = run_with_stub(StubType::FromLeo, source);
255	    let from_aleo_output = run_with_stub(StubType::FromAleo, source);
256	
257	    if from_leo_output != from_aleo_output {
258	        format!(
259	            "{from_leo_output}\n\n\
260	             ---\n\
261	             Note: Treating dependencies as Aleo produces different results:\n\n\
262	             {from_aleo_output}"
263	        )
264	    } else {
265	        from_leo_output
266	    }
267	}
268	
269	/// Runs a single test pass with the given stub type and returns all diagnostics
270	/// (errors, warnings, and output) as a single formatted string.
271	fn run_with_stub(stub: StubType, source: &str) -> String {
272	    let buf = BufferEmitter::new();
273	    let handler = Handler::new(buf.clone());
274	    let node_builder = Rc::new(NodeBuilder::default());
275	
276	    create_session_if_not_set_then(|_| {
277	        match run_test(stub, source, &handler, &node_builder) {
278	            Ok(output) => {
279	                // Successful compilation: warnings (if any) followed by output
280	                format!("{}{}", buf.extract_warnings(), output)
281	            }
282	            Err(()) => {
283	                // Failed compilation: errors first, then warnings
284	                format!("{}{}", buf.extract_errs(), buf.extract_warnings())
285	            }
286	        }
287	    })
288	}
289	
290	#[test]
291	#[serial]
292	fn test_compiler() {
293	    leo_test_framework::run_tests("compiler", runner);
294	}
